import{_ as e,o as s,c as i,a1 as n}from"./chunks/framework.BwhMLafE.js";const g=JSON.parse('{"title":"Writing a Language","description":"","frontmatter":{},"headers":[],"relativePath":"writing_a_language.md","filePath":"writing_a_language.md"}'),t={name:"writing_a_language.md"};function l(r,a,o,p,d,h){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="writing-a-language" tabindex="-1">Writing a Language <a class="header-anchor" href="#writing-a-language" aria-label="Permalink to &quot;Writing a Language&quot;">â€‹</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">â€‹</a></h2><ul><li><a href="#directory-structure">Directory Structure</a><ul><li><a href="#getting-started">Getting Started</a></li></ul></li><li><a href="#the-grammar-file">The Grammar File</a><ul><li><a href="#example-simple-arithmetic">Example: Simple Arithmetic</a></li></ul></li><li><a href="#hooks-in-procedureszig">Hooks in procedures.zig</a><ul><li><a href="#common-hook-conventions">Common Hook Conventions</a></li><li><a href="#writing-custom-hooks">Writing Custom Hooks</a></li></ul></li><li><a href="#build-and-run">Build and Run</a></li><li><a href="#parsing-verbose-output">Parsing Verbose Output</a></li><li><a href="#conventions-and-tips">Conventions and Tips</a></li></ul><hr><p>This guide covers how to scaffold a new grammar directory for a custom language.</p><hr><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">â€‹</a></h2><p>Each language lives under <code>languages/&lt;name&gt;/</code>. The build system automatically discovers languages by scanning for a <code>_ll-parser.zig</code> or <code>_lr-parser.zig</code> file.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>languages/</span></span>
<span class="line"><span>â””â”€â”€ mylang/</span></span>
<span class="line"><span>    â”śâ”€â”€ ll.grm          # LL grammar rules (for top-down parsing)</span></span>
<span class="line"><span>    â”śâ”€â”€ lr.grm          # LR grammar rules (for bottom-up parsing)</span></span>
<span class="line"><span>    â”śâ”€â”€ sample-code.txt # Test input â€” will be parsed each build</span></span>
<span class="line"><span>    â”śâ”€â”€ _ll-parser.zig  # Auto-generated by the grammar generator</span></span>
<span class="line"><span>    â”śâ”€â”€ _lr-parser.zig  # Auto-generated by the grammar generator</span></span>
<span class="line"><span>    â””â”€â”€ procedures.zig  # Required: hook functions and runtime payload definition</span></span></code></pre></div><h3 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">â€‹</a></h3><p>Run all commands from the root directory of the repository:</p><ol><li><p>Create a new directory under <code>languages/</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/mylang</span></span></code></pre></div></li><li><p>Define your grammar in <code>languages/mylang/ll.grm</code> (or <code>lr.grm</code>). See <a href="./grammar_guidelines.html">Grammar Guidelines</a> for syntax and rules.</p></li><li><p>Write your <code>languages/mylang/procedures.zig</code> file. At a minimum, this file must define <code>indentation_syntax</code> and <code>Payload</code>:</p><div class="language-zig vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">zig</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> const</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> indentation_syntax</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> const</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> Payload</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {};</span></span></code></pre></div></li><li><p>Add a <code>sample-code.txt</code> with an example input so the parser has something to parse on every build.</p></li><li><p>Generate the parser tables:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/generate-parser</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --language</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/mylang</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parser-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LL</span></span></code></pre></div></li></ol><hr><h2 id="the-grammar-file" tabindex="-1">The Grammar File <a class="header-anchor" href="#the-grammar-file" aria-label="Permalink to &quot;The Grammar File&quot;">â€‹</a></h2><p>The grammar file format is documented in detail in <a href="./grammar_guidelines.html">Grammar Guidelines</a>. Key points:</p><ul><li><strong>Entry point:</strong> The first rule defined in the file becomes the parser&#39;s start symbol.</li><li><strong>Parser type:</strong> Write <code>ll.grm</code> for top-down (LL) parsing, <code>lr.grm</code> for bottom-up (LR) parsing.</li><li><strong>AST allocation:</strong> Variables starting with a capital letter allocate AST nodes; variables starting with <code>_</code> (CamelCase, e.g. <code>_WhiteSpace</code>) are skipped entirely.</li><li><strong>Terminals:</strong> Exact string literals must be in double quotes (e.g. <code>&quot;let&quot;</code>). Unquoted lowercase identifiers match named character classes or generative terminals like <code>digit</code>, <code>letter</code>, <code>space</code>, <code>new_line</code> (these can optionally receive exception suffix chains like <code>character^&quot;\\n&quot;</code> or <code>digit^&quot;1&quot;^&quot;3&quot;</code> to exclude specific characters, see <a href="./grammar_guidelines.html">Grammar Guidelines</a> for details).</li></ul><h3 id="example-simple-arithmetic" tabindex="-1">Example: Simple Arithmetic <a class="header-anchor" href="#example-simple-arithmetic" aria-label="Permalink to &quot;Example: Simple Arithmetic&quot;">â€‹</a></h3><p><code>languages/mylang/ll.grm</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Definition</span></span>
<span class="line"><span>| &quot;let&quot; _WhiteSpace Expr _WhiteSpace</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Expr</span></span>
<span class="line"><span>| Number</span></span>
<span class="line"><span>| &quot;+&quot; Number</span></span>
<span class="line"><span>| &quot;-&quot; Number</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Number</span></span>
<span class="line"><span>| &quot;4&quot;</span></span>
<span class="line"><span>| &quot;2&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>_WhiteSpace</span></span>
<span class="line"><span>| space _WhiteSpace</span></span>
<span class="line"><span>| new_line _WhiteSpace</span></span>
<span class="line"><span>|</span></span></code></pre></div><p><code>languages/mylang/sample-code.txt</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let +4</span></span></code></pre></div><hr><h2 id="hooks-in-procedures-zig" tabindex="-1">Hooks in procedures.zig <a class="header-anchor" href="#hooks-in-procedures-zig" aria-label="Permalink to &quot;Hooks in procedures.zig&quot;">â€‹</a></h2><p>During parsing, you can execute custom Zig logic (known as reduction procedures or hooks) when grammar rules are matched and reduced. These hooks are exported from your language&#39;s <code>procedures.zig</code> file.</p><p>To learn how to register explicit/implicit hooks, how to write custom procedures in Zig, and how they map to AST generation options, see the dedicated <a href="./procedures.html">Reduction Procedures User Guide</a>.</p><hr><h2 id="build-and-run" tabindex="-1">Build and Run <a class="header-anchor" href="#build-and-run" aria-label="Permalink to &quot;Build and Run&quot;">â€‹</a></h2><h3 id="generate-ll-parser" tabindex="-1">Generate LL Parser <a class="header-anchor" href="#generate-ll-parser" aria-label="Permalink to &quot;Generate LL Parser&quot;">â€‹</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/generate-parser</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --language</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/mylang</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parser-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LL</span></span></code></pre></div><h3 id="generate-lr-parser" tabindex="-1">Generate LR Parser <a class="header-anchor" href="#generate-lr-parser" aria-label="Permalink to &quot;Generate LR Parser&quot;">â€‹</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/generate-parser</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --language</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/mylang</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parser-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LR</span></span></code></pre></div><h3 id="build-and-run-1" tabindex="-1">Build and Run <a class="header-anchor" href="#build-and-run-1" aria-label="Permalink to &quot;Build and Run&quot;">â€‹</a></h3><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ll-mylang</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/mylang/sample-code.txt</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lr-mylang</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/mylang/sample-code.txt</span></span></code></pre></div><p>The executable will be built automatically â€” <code>build.zig</code> scans the <code>languages/</code> directory for any subdirectory containing a <code>_ll-parser.zig</code> or <code>_lr-parser.zig</code> file.</p><hr><h2 id="parsing-verbose-output" tabindex="-1">Parsing Verbose Output <a class="header-anchor" href="#parsing-verbose-output" aria-label="Permalink to &quot;Parsing Verbose Output&quot;">â€‹</a></h2><p>Pass <code>--verbosity 1</code> (or <code>2</code>) to the generated executable to print the resulting AST alongside benchmark metrics:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ll-json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/json/samples/code-01.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbosity</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><hr><h2 id="conventions-and-tips" tabindex="-1">Conventions and Tips <a class="header-anchor" href="#conventions-and-tips" aria-label="Permalink to &quot;Conventions and Tips&quot;">â€‹</a></h2><ul><li>Keep your grammar in alphabetical rule order; the generator may depend on it.</li><li>Use <code>_</code>-prefixed CamelCase helper rules (like <code>_WhiteSpace</code> or <code>_Tail</code>) for whitespace, trailing symbols, and optional parts â€” they incur zero overhead.</li><li>If your language needs to handle both LL and LR, write both <code>ll.grm</code> and <code>lr.grm</code> with equivalent grammars in each.</li><li>Remember that the first rule in the file is the entry point â€” no explicit <code>@start</code> annotation is needed.</li><li>Check that all your terminal symbols match what the grammar generator expects (<code>digit</code>, <code>letter</code>, <code>space</code>, <code>new_line</code>, <code>operator</code>, etc.).</li></ul>`,42)])])}const u=e(t,[["render",l]]);export{g as __pageData,u as default};
